const data = items[0].json.results;

// Extract relevant pollutants and measurements
const pollutants = data.map(location => {
  return location.measurements.reduce((acc, m) => {
    acc[m.parameter] = m.value;
    return acc;
  }, { location: location.location, city: location.city, coordinates: location.coordinates });
});

return pollutants.map(pollutant => ({ json: pollutant }));

/*
  Simulate AI analysis on pollution patterns.
  E.g., Determine pollution levels, trends, and suggest alerts severity.
*/
const analyzedItems = items.map(item => {
  const json = item.json;

  // Analyze PM2.5 for severity
  const pm25 = json.pm25 || 0;
  let severity = 'Low';
  if (pm25 > 75) severity = 'High';
  else if (pm25 > 35) severity = 'Moderate';

  // Recommend alert messages based on severity
  const alertMessage = {
    Low: 'Air quality is good. Enjoy your outdoor activities!',
    Moderate: 'Air quality is moderate. Sensitive groups should reduce prolonged exertion outdoors.',
    High: 'Air quality is poor. Everyone should limit outdoor activities.'
  }[severity];

  return {
    json: {
      location: json.location,
      city: json.city,
      coordinates: json.coordinates,
      pollution: {
        pm25,
        severity
      },
      alertMessage
    }
  };
});

return analyzedItems;

/*
  Generate personalized health and environmental recommendations per location.
  Example basic heuristic logic:
*/
const healthRecommendations = items.map(item => {
  const { severity, pm25 } = item.json.pollution;
  let recommendations = [];

  if (severity === 'High') {
    recommendations.push('Wear N95 masks when going outside.');
    recommendations.push('Use air purifiers indoors.');
    recommendations.push('Avoid outdoor exercise.');
  } else if (severity === 'Moderate') {
    recommendations.push('Consider wearing masks during prolonged outdoor activities.');
    recommendations.push('Keep windows closed if sensitive.');
  } else {
    recommendations.push('Air quality is safe. Maintain healthy lifestyle.');
  }

  // Environmental action recommendations
  if (pm25 > 35) {
    recommendations.push('Support local initiatives to reduce traffic and emissions.');
  } else {
    recommendations.push('Participate in local green activities and tree planting.');
  }

  return {
    json: {
      ...item.json,
      recommendations
    }
  };
});

return healthRecommendations;
